const raw = $('Webhook').first().json.body || {};
const enhanced = $input.first().json.message?.content || raw.prompt || 'a beautiful landscape';
const channelId = raw.channel || raw.channel_id || 'C0AKW7W9ZPX';
const userId    = raw.user_id || raw.user || '';
const clientId  = 'n8n-img-' + Date.now();
const seed = Math.floor(Math.random() * 1_000_000_000);

// FLUX.1-schnell FP8 ComfyUI workflow
const workflow = {
  "6":  { "inputs": {"text": enhanced, "clip": ["11",0]}, "class_type": "CLIPTextEncode" },
  "8":  { "inputs": {"samples": ["13",0], "vae": ["10",0]}, "class_type": "VAEDecode" },
  "9":  { "inputs": {"filename_prefix": "n8n_flux", "images": ["8",0]}, "class_type": "SaveImage" },
  "10": { "inputs": {"vae_name": "ae.safetensors"}, "class_type": "VAELoader" },
  "11": { "inputs": {"clip_name1": "clip_l.safetensors", "clip_name2": "t5xxl_fp8_e4m3fn.safetensors", "type": "flux"}, "class_type": "DualCLIPLoader" },
  "13": { "inputs": {"noise":["25",0],"guider":["22",0],"sampler":["16",0],"sigmas":["17",0],"latent_image":["27",0]}, "class_type": "SamplerCustomAdvanced" },
  "16": { "inputs": {"sampler_name": "euler"}, "class_type": "KSamplerSelect" },
  "17": { "inputs": {"scheduler": "simple", "steps": 4, "denoise": 1.0, "model": ["30",0]}, "class_type": "BasicScheduler" },
  "22": { "inputs": {"model": ["30",0], "conditioning": ["6",0]}, "class_type": "BasicGuider" },
  "25": { "inputs": {"noise_seed": seed}, "class_type": "RandomNoise" },
  "27": { "inputs": {"width": 1024, "height": 1024, "batch_size": 1}, "class_type": "EmptySD3LatentImage" },
  "30": { "inputs": {"unet_name": "flux1-schnell-fp8.safetensors", "weight_dtype": "fp8_e4m3fn"}, "class_type": "UNETLoader" }
};

return [{ json: { workflow, clientId, channelId, userId, prompt: enhanced } }];

const promptId  = $input.first().json.prompt_id;
const buildData = $('Build ComfyUI Payload').first().json;
const maxTries  = 72;          // 6 min @ 5s each

for (let i = 0; i < maxTries; i++) {
  await new Promise(r => setTimeout(r, 5000));
  const history = await $helpers.httpRequest({
    method: 'GET',
    url: `http://host.docker.internal:8188/history/${promptId}`
  });
  const entry = history[promptId];
  if (entry?.status?.completed) {
    const imageNode = Object.values(entry.outputs || {}).find(o => o.images?.length);
    if (imageNode) {
      const img = imageNode.images[0];
      return [{ json: { uploadComment: ':frame_with_picture: *' + (prompt || 'Generated image').slice(0,120) + '*\n_FLUX on RTX 5070 Ti_',
        promptId,
        filename:  img.filename,
        subfolder: img.subfolder || '',
        type:      img.type || 'output',
        channelId: buildData.channelId,
        userId:    buildData.userId,
        prompt:    buildData.prompt
      }}];
    }
  }
}
throw new Error('ComfyUI generation timed out after 6 minutes');

const https = require('https');

function httpsReq(options, body) {
  return new Promise((resolve, reject) => {
    if (Buffer.isBuffer(body)) {
      options.headers = options.headers || {};
      options.headers['Content-Length'] = body.length;
    }
    const req = https.request(options, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        const text = Buffer.concat(chunks).toString();
        try { resolve(JSON.parse(text)); } catch { resolve({ _raw: text }); }
      });
    });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const token = $env.SLACK_BOT_TOKEN;
const item = $input.first();
const b64 = item.binary && item.binary.data ? item.binary.data.data : null;

if (!b64) {
  return [{ json: { ...item.json, fileId: null, uploaded: false } }];
}

const buf = Buffer.from(b64, 'base64');
const mimeType = (item.binary.data.mimeType) || 'application/octet-stream';
const fileName = (item.binary.data.fileName) || 'file.bin';

// Step 1: Get upload URL
const body1 = `filename=${encodeURIComponent(fileName)}&length=${buf.length}`;
const urlData = await httpsReq({
  method: 'POST',
  hostname: 'slack.com',
  path: '/api/files.getUploadURLExternal',
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/x-www-form-urlencoded',
    'Content-Length': Buffer.byteLength(body1),
  }
}, Buffer.from(body1));

if (!urlData.ok) throw new Error(`getUploadURL failed: ${JSON.stringify(urlData)}`);
const { upload_url, file_id } = urlData;

// Step 2: PUT binary to upload URL
// Parse upload_url without URL class (not available in sandbox)
const urlMatch = upload_url.match(/^https?:\/\/([^\/]+)(\/[^?]*)?(\?.*)?$/);
const uploadHostname = urlMatch[1];
const uploadPath = (urlMatch[2] || '/') + (urlMatch[3] || '');

await httpsReq({
  method: 'PUT',
  hostname: uploadHostname,
  path: uploadPath,
  headers: {
    'Content-Type': mimeType,
    'Content-Length': buf.length,
  }
}, buf);

// Step 3: Complete upload
const channelId = item.json.channelId || '';
const comment = item.json.uploadComment || '';
const completeBody = JSON.stringify({
  files: [{ id: file_id }],
  ...(channelId ? { channel_id: channelId } : {}),
  ...(comment ? { initial_comment: comment } : {}),
});

await httpsReq({
  method: 'POST',
  hostname: 'slack.com',
  path: '/api/files.completeUploadExternal',
  headers: {
    'Authorization': `Bearer ${token}`,
    'Content-Type': 'application/json',
    'Content-Length': Buffer.byteLength(completeBody),
  }
}, Buffer.from(completeBody));

return [{ json: { ...item.json, fileId: file_id, uploaded: true } }];

// Restore context from Poll Until Done node (HTTP Request dropped it)
const poll = $('Poll Until Done').first().json;
const item = $input.first();
return [{
  json: {
    channelId: poll.channelId || '',
    filename: poll.filename || 'file',
    prompt: poll.prompt || '',
    uploadComment: poll.uploadComment || '{}'
  },
  binary: item.binary
}];
